extension.valueString:
/*
@internal: Polio containing Doses Administered to Patient that are in the Primary series
*/
define "Polio Primary Series Doses Administered to Patient":
  "Polio Doses Administered to Patient".seriesPrimary()

/*
@internal: Polio IPV Primary Series Doses Administered to Patient
*/
define "Polio IPV Primary Series Doses Administered to Patient":
  "Polio Primary Series Doses Administered to Patient" I
  where I.typeOfDose() ~ Concepts."IPV"

/*
@numerator: Number of IPV doses (3rd dose) administered through routine services during the reporting period
@pseudocode: COUNT of immunization events WHERE "Vaccine type" = "Inactivated polio vaccines" for the 3rd dose in the primary series AND "Date and time of vaccination" is during the reporting period
*/
define "Numerator":
  Coalesce( Polio."Polio IPV Primary Series Doses Administered to Patient".sortedIndex(2).occurrence.toInterval() starts during "Measurement Period",
    false )

/*
@stratifier: By Geographic Region of Patient Stratifier
*/
define "By Geographic Region Stratifier":
    First(Patient.address A where A.use in { 'home' }).state

/*
@denominator: Number in target group
@pseudocode: As defined by the Member States
*/
define "Denominator":
  true
